/* Aula 37 — modelJs: class vs factory */

// 1) Class
class Contador {
  constructor() {
    this.valor = 0;
  }
  inc() {
    this.valor++;
  }
  dec() {
    this.valor--;
  }
  toString() {
    return `Valor: ${this.valor}`;
  }
}

const c1 = new Contador();
const c2 = new Contador();

c1.inc();
c1.inc();
console.log('c1:', c1.toString());
console.log('c2:', c2.toString());

// 2) Factory
function criarContador() {
  let valor = 0;
  return {
    inc() { valor++; },
    dec() { valor--; },
    toString() { return `Valor: ${valor}`; }
  };
}

const f1 = criarContador();
const f2 = criarContador();

f1.inc();
console.log('f1:', f1.toString());
console.log('f2:', f2.toString());
